(()=>{
'use strict';
if(window.__ADMIN_PERFORMANCE_ACTIVE_V2__)return;
window.__ADMIN_PERFORMANCE_ACTIVE_V2__=true;
const nativeFetch=window.fetch.bind(window);let lastPayload=null;
if(window.XLSX&&!window.__PERF_XLSX_PATCH__){window.__PERF_XLSX_PATCH__=true;const old=window.XLSX.read;window.XLSX.read=function(){const wb=old.apply(this,arguments);try{window.__PERF_LAST_WB=wb}catch{}return wb}}
const T=v=>String(v??'').trim(),K=v=>T(v).replace(/\s+/g,'').toLowerCase(),N=v=>typeof v==='number'?(isFinite(v)?v:0):(Number(T(v).replace(/,/g,'').replace(/%/g,'').replace(/[^0-9.\-]/g,''))||0),P=v=>{v=N(v);return v&&v<=1.5?v*100:v};
function wd(){try{const s=window.__PERF_LAST_WB?.Sheets?.['Seller Report'];const v=c=>s?.[c]?.v??s?.[c]?.w??'';return{totalWorkdays:N(v('D4')),workdayNo:N(v('D5'))}}catch{return{}}}
function pick(o,n){const ks=Object.keys(o||{});for(const x of n){let k=ks.find(a=>K(a)===K(x));if(k)return o[k]}for(const x of n){let k=ks.find(a=>K(a).includes(K(x)));if(k)return o[k]}return''}
function metric(o,t,a,i){const target=N(pick(o,t)),actual=N(pick(o,a));return{target,actual,index:P(N(pick(o,i)))||(target?actual/target*100:0)}}
function minRow(r){const o=r.sellerReport||{};return{ads:r.adsCode,ps:r.psCode,name:r.psName,branch:r.branch,type:pick(o,['Type']),sales:metric(o,['เป้าหมายยอดขาย'],['ยอดขายใน Doit'],['Index']),giv:metric(o,['Target Volume GIV'],['Volume GIV'],['Index Volume GIV']),moq:{target:0,actual:N(pick(o,['การกระจาย SBD MOQ'])),index:P(N(pick(o,['Index MOQ 75%','Index MOQ'])))},dc1:metric(o,['เป้าหมาย CD1 RJ SH RH JJ 70ML'],['การกระจาย CD1 RJ SH RH JJ 70ML'],['Index CD1 RJ SH RH JJ 70ML']),dc2:metric(o,['เป้าหมาย CD2 DN FE SF 450ML'],['การกระจาย CD2 DN FE SF 450ML'],['Index CD2 DN FE SF 450ML']),dc3:metric(o,['เป้าหมาย CD3 GL Blue2 Flexi'],['การกระจาย CD3 GL Blue2 Flexi'],['Index CD3 GL Blue2 Flexi']),cd13:metric(o,['Target CD1+CD3'],['การกระจาย CD1+CD3'],['Index CD1+CD3']),bills:metric(o,['เป้าหมายบิลซื้อทั้งหมด'],['จำนวนบิลซื้อทั้งหมด'],[]),gps:{target:0,actual:P(N(pick(o,['% GPS Compliance เฉลี่ยทั้งเดือน']))),index:P(N(pick(o,['% GPS Compliance เฉลี่ยทั้งเดือน'])))},dgp:metric(o,['เป้าหมาย Golden Point'],['Golden Point'],['Index'])}}
function sum(rows,code,name){const keys=['sales','giv','moq','dc1','dc2','dc3','cd13','bills','gps','dgp'],r={code,name:name||code};keys.forEach(k=>{let t=0,a=0,ix=0,c=0;rows.forEach(x=>{t+=N(x[k]?.target);a+=N(x[k]?.actual);ix+=N(x[k]?.index);c++});r[k]={target:t,actual:a,index:t?a/t*100:(c?ix/c:0)}});return r}
function ranks(rows){const keys=['sales','giv','moq','dc1','dc2','dc3','cd13','bills','gps','dgp'],o={};keys.forEach(k=>o[k]=[...rows].sort((a,b)=>N(b[k]?.index)-N(a[k]?.index)).map(x=>({ads:x.ads||x.code,ps:x.ps||x.code,name:x.name,target:N(x[k]?.target),actual:N(x[k]?.actual),index:N(x[k]?.index)})));return o}
function buildMin(data){const ps=(data.ps||[]).map(minRow),codes=[...new Set(ps.map(x=>x.ads).filter(Boolean))].sort(),ads=codes.map(c=>({...sum(ps.filter(x=>x.ads===c),c,c),ads:c,ps:c})),ds=sum(ps,'DS','DS'),w=wd();return{meta:{schema:'performance-min-v1',source:data.source||'',updatedAt:new Date().toISOString(),reportDate:data.reportDate||'',workdayNo:N(data.workdayNo||data.meta?.workdayNo)||w.workdayNo,totalWorkdays:N(data.totalWorkdays||data.meta?.totalWorkdays)||w.totalWorkdays},ds,ads,ps,ms:data.ms||[],rank:{ads:ranks(ads),ps:ranks(ps)}}}
function reportDate(data,path){if(data&&data.reportDate)return data.reportDate;const fromPath=String(path||'').match(/performance\/(20\d{2}-\d{2}-\d{2})\//);if(fromPath)return fromPath[1];return new Date().toISOString().slice(0,10)}
async function digest(text){try{const b=await crypto.subtle.digest('SHA-256',new TextEncoder().encode(text));return Array.from(new Uint8Array(b)).map(x=>x.toString(16).padStart(2,'0')).join('')}catch{return''}}
async function bodyText(body){if(!body)return'';if(typeof body==='string')return body;if(body instanceof Blob)return await body.text();return''}
function objectPath(url){const s=String(url||''),m=s.match(/\/storage\/v1\/object\/doit-files\/(.+)$/);return m?decodeURIComponent(m[1]).replace(/^\/+/, ''):''}
async function putLike(activeUrl,headers,path,obj){const u=String(activeUrl).replace(/performance\/active\.json.*$/,'')+path;return nativeFetch(u,{method:'POST',headers:{...headers,'Content-Type':'application/json','x-upsert':'true'},body:new Blob([JSON.stringify(obj)],{type:'application/json'}),cache:'no-store'}).catch(()=>null)}
async function extraFiles(url,headers,data){try{const min=buildMin(data),d=new Date(),mon=(min.meta.reportDate||d.toISOString().slice(0,10)).slice(0,7).replace('-',''),wdn=min.meta.workdayNo||d.getDate(),cmp=`performance/compare/${mon}-WD${String(wdn).padStart(2,'0')}.json`;await putLike(url,headers,'performance/current.min.json',min);let hist=[];try{const r=await nativeFetch(String(url).replace(/performance\/active\.json.*$/,'')+'performance/history-index.json',{headers,cache:'no-store'});if(r.ok)hist=await r.json()}catch{}hist=[{period:mon,workdayNo:wdn,totalWorkdays:min.meta.totalWorkdays,path:cmp,updatedAt:min.meta.updatedAt,totalActual:min.ds.sales.actual,totalTarget:min.ds.sales.target},...(Array.isArray(hist)?hist:[]).filter(x=>x.path!==cmp)].slice(0,31);await putLike(url,headers,cmp,min);await putLike(url,headers,'performance/history-index.json',hist)}catch(e){console.warn('performance min skipped',e)}}
window.fetch=async(input,opt={})=>{const url=String(typeof input==='string'?input:input?.url||''),method=String(opt?.method||'GET').toUpperCase(),path=objectPath(url);if(method==='POST'&&/^performance\//.test(path)&&/\.json$/.test(path)&&!/^performance\/(active|index|current\.min|history-index)\.json$/.test(path)){const text=await bodyText(opt.body);try{const data=JSON.parse(text),rd=reportDate(data,path),hash=await digest(text);data.reportDate=rd;data.hash=hash;data.dataSchemaVersion=2;data.currentDataPath=path;lastPayload={path,reportDate:rd,hash,data};opt={...opt,body:new Blob([JSON.stringify(data)],{type:'application/json'})}}catch{}}
 if(method==='POST'&&path==='performance/active.json'){const text=await bodyText(opt.body);try{const incoming=JSON.parse(text),oldRes=await nativeFetch(url,{headers:opt.headers,cache:'no-store'}).catch(()=>null);let old=null;if(oldRes&&oldRes.ok)old=await oldRes.json().catch(()=>null);const currentPath=lastPayload?.path||incoming.dataPath||'',rd=lastPayload?.reportDate||reportDate(lastPayload?.data,currentPath),oldPath=old?.dataPath||old?.currentDataPath||'',oldDate=old?.reportDate||reportDate(null,oldPath),previousDataPath=oldPath&&oldDate!==rd?oldPath:(old?.previousDataPath||''),history=[{reportDate:oldDate,dataPath:oldPath,versionId:old?.versionId||'',updatedAt:old?.updatedAt||''},...(old?.history||[])].filter(x=>x.dataPath).slice(0,30),active={...incoming,schema:'performance-active-v2',reportDate:rd,revision:oldDate===rd?Number(old?.revision||1)+1:1,hash:lastPayload?.hash||'',dataPath:currentPath,currentDataPath:currentPath,latestPath:currentPath,previousDataPath,updatedAt:new Date().toISOString(),counts:{ads:incoming.adsCount||lastPayload?.data?.ads?.length||0,ps:incoming.psCount||lastPayload?.data?.ps?.length||0,ms:incoming.msCount||lastPayload?.data?.ms?.length||0},history};if(lastPayload?.data)extraFiles(url,opt.headers,lastPayload.data);opt={...opt,body:new Blob([JSON.stringify(active)],{type:'application/json'})}}catch{}}
 return nativeFetch(input,opt)};
})();